return items.map(item => {
    const data = item.json;
    let content = "";
    let metadata = {};

    // Tab 1: Services & Pricing
    if (data.Service && data.Description) {
        content = `Service: ${data.Service}
Description: ${data.Description}
Price Range: ${data.Price_Range}
Duration: ${data.Duration}
Emergency Available: ${data.Emergency_Available}`;

        metadata = {
            type: "service",
            service: data.Service,
            price_range: data.Price_Range,
            emergency: data.Emergency_Available
        };
    } 

    // Tab 2: Service Areas
    else if (data.City && data.Service_Type) {
        content = `Service Area: ${data.City}
Zip Codes: ${data.Zip_Codes}
Service Type: ${data.Service_Type}
Notes: ${data.Notes || ""}`;

        metadata = {
            type: "service_area",
            city: data.City,
            service_type: data.Service_Type
        };
    } 

    // Tab 3: FAQ
    else if (data.Question && data.Answer && data.Category) {
        content = `Question: ${data.Question}
Answer: ${data.Answer}
Category: ${data.Category}`;

        metadata = {
            type: "faq",
            category: data.Category
        };
    } 

    // Tab 4: Diagnostics
    else if (data.Symptom && data.Follow_Up_Questions) {
        content = `Symptom: ${data.Symptom}
Follow-Up Questions: ${data.Follow_Up_Questions}
Likely Issue: ${data.Likely_Issue || ""}
Urgency: ${data.Urgency}`;

        metadata = {
            type: "diagnostic",
            symptom: data.Symptom,
            urgency: data.Urgency
        };
    } 

    // Tab 5: Company Info
    else if (data.Field && data.Value) {
        content = `${data.Field}: ${data.Value}`;

        metadata = {
            type: "company_info",
            field: data.Field
        };
    }

    // Fallback for any other data
    else {
        content = JSON.stringify(data);
        metadata = { type: "other" };
    }

    return {
        json: {
            content: content,
            metadata: metadata
        }
    };
});
